  2348→      const trainProjections = await this.projectTrainPMs(
  2349→        train,
  2350→        trainRules,
  2351→        trainHistory,
  2352→        horizonEnd,
  2353→        dailyKm
  2354→      );
  2355→      
  2356→      requirements.push(...trainProjections);
  2357→    }
  2358→    
  2359→    return requirements;
  2360→  }
  2361→  
  2362→  /**
  2363→   * Project all PM events for a single train over the horizon.
  2364→   */
  2365→  private async projectTrainPMs(
  2366→    train: Train,
  2367→    pmRules: PMType[],
  2368→    pmHistory: PMHistory[],
  2369→    horizonEnd: Date,
  2370→    dailyKm: number
  2371→  ): Promise<PMRequirement[]> {
  2372→    const projections: PMRequirement[] = [];
  2373→    
  2374→    // Create working state (mutable copy of history + projections)
  2375→    let workingHistory = [...pmHistory];
  2376→    let currentMileage = train.currentMileageKm;
  2377→    let currentDate = new Date();
  2378→    
  2379→    // Project until we exceed horizon
  2380→    while (currentDate < horizonEnd) {
