  2390→        const projection = this.calculateNextPMDue(
  2391→          train,
  2392→          rule,
  2393→          pmRules,
  2394→          workingHistory,
  2395→          currentMileage,
  2396→          currentDate,
  2397→          dailyKm
  2398→        );
  2399→        
  2400→        if (!nextPM || projection.date < nextPM.date) {
  2401→          nextPM = {
  2402→            rule,
  2403→            date: projection.date,
  2404→            mileage: projection.mileage,
  2405→            trigger: projection.trigger
  2406→          };
  2407→        }
  2408→      }
  2409→      
  2410→      if (!nextPM || nextPM.date > horizonEnd) break;
  2411→      
