  2413→      const requirement: PMRequirement = {
  2414→        id: generateUUID(),
  2415→        trainId: train.id,
  2416→        trainNumber: train.trainNumber,
  2417→        pmTypeId: nextPM.rule.id,
  2418→        pmCode: nextPM.rule.pmCode,
  2419→        projectedDate: nextPM.date,
  2420→        projectedMileageKm: nextPM.mileage,
  2421→        triggerType: nextPM.trigger,
  2422→        confidence: workingHistory.length > 0 ? 'HISTORICAL' : 'ESTIMATED',
  2423→        estimatedHours: nextPM.rule.estimatedHours,
  2424→        trackType: nextPM.rule.trackType,
  2425→        durationDays: nextPM.rule.minTrackDays,
  2426→        // Compliance window (Ã‚Â±10% of interval by default)
  2427→        constraintStart: addDays(nextPM.date, -Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm)),
  2428→        constraintEnd: addDays(nextPM.date, Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm))
  2429→      };
