  2445→      currentMileage = nextPM.mileage + (nextPM.rule.minTrackDays * dailyKm * 0.1);
  2446→    }
  2447→    
  2448→    return projections;
  2449→  }
  2450→  
  2451→  /**
  2452→   * Calculate when the next instance of a specific PM type is due.
  2453→   * 
  2454→   * CRITICAL: Accounts for PM hierarchy - a C4 satisfies C1/C2/C3 requirements,
  2455→   * so the mileage counter resets from the C4 completion point.
  2456→   * 
  2457→   * CRITICAL: Handles "Cold Start" case where train has no PM history.
  2458→   * Without this fix, trains with high mileage and no history would show
  2459→   * ALL PMs as overdue immediately.
  2460→   */
  2461→  private calculateNextPMDue(
  2462→    train: Train,
  2463→    targetRule: PMType,
  2464→    allRules: PMType[],
  2465→    history: PMHistory[],
  2466→    currentMileage: number,
  2467→    currentDate: Date,
  2468→    dailyKm: number
  2469→  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {
  2470→    
  2471→    // 1. Find all PM types that SATISFY the target PM
  2472→    // (the target itself + any higher-level PM that includes target in satisfiesCodes)
  2473→    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);
  2474→    
  2475→    // 2. Find the most recent PM that satisfies this requirement
  2476→    const lastSatisfying = history
  2477→      .filter(h => satisfyingCodes.includes(h.pmCode))
  2478→      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];
  2479→    
  2480→    // 3. Handle "Cold Start" - no PM history exists
  2481→    //    Assume train has been maintained on schedule since commissioning.
  2482→    //    Calculate which cycle we're currently in and when it started.
  2483→    let lastMileage: number;
  2484→    let lastDate: Date;
  2485→    
  2486→    if (lastSatisfying) {
  2487→      // Normal case: use actual history
  2488→      lastMileage = lastSatisfying.mileageAtCompletion;
  2489→      lastDate = new Date(lastSatisfying.completionDate);
  2490→    } else {
  2491→      // COLD START FIX: Create "virtual" last PM
  2492→      // Calculate how many complete cycles since commissioning
  2493→      const cyclesCompleted = Math.floor(currentMileage / targetRule.intervalKm);
  2494→      
  2495→      if (cyclesCompleted > 0) {
  2496→        // Assume last PM occurred at start of current cycle
  2497→        lastMileage = cyclesCompleted * targetRule.intervalKm;
  2498→        // Estimate when that mileage was reached
  2499→        const daysAgo = (currentMileage - lastMileage) / dailyKm;
  2500→        lastDate = addDays(currentDate, -daysAgo);
  2501→      } else {
  2502→        // Train hasn't completed first cycle yet - use commissioning as baseline
  2503→        lastMileage = 0;
  2504→        lastDate = train.commissioningDate;
  2505→      }
  2506→    }
  2507→    
  2508→    // 4. Calculate mileage-based due date
  2509→    const kmSinceLast = currentMileage - lastMileage;
  2510→    const kmRemaining = Math.max(0, targetRule.intervalKm - kmSinceLast);
  2511→    const daysUntilMileageDue = kmRemaining / dailyKm;
  2512→    const dateByMileage = addDays(currentDate, daysUntilMileageDue);
  2513→    const mileageAtDue = currentMileage + kmRemaining;
  2514→    
  2515→    // 5. Calculate time-based due date (if interval defined)
  2516→    let dateByTime: Date | null = null;
  2517→    if (targetRule.intervalMonths) {
  2518→      dateByTime = addMonths(lastDate, targetRule.intervalMonths);
  2519→    }
  2520→    
  2521→    // 6. Return whichever comes first (dual trigger)
  2522→    if (dateByTime && dateByTime < dateByMileage) {
  2523→      const daysUntilTime = differenceInDays(dateByTime, currentDate);
  2524→      const mileageAtTime = currentMileage + (Math.max(0, daysUntilTime) * dailyKm);
  2525→      return { date: dateByTime, mileage: mileageAtTime, trigger: 'TIME' };
  2526→    } else {
  2527→      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
  2528→    }
  2529→  }
  2530→  
