## 4.10 Costing Service

### 4.10.1 Purpose

Calculate TCO projections, track variance against budget, and provide cost impact analysis for adjustments.

### 4.10.2 Implementation

```typescript
interface CostBreakdown {
  laborCost: number;
  overtimeCost: number;
  materialCost: number;
  contractorCost: number;
  overheadCost: number;
  totalCost: number;
}

class CostingService {
  async calculatePMCost(
    pmScheduleId: string,
    includeProjected: boolean = false
  ): Promise<CostBreakdown> {
    const pm = await this.db.query.pmSchedule.findFirst({
      where: eq(pmSchedule.id, pmScheduleId),
      with: {
        pmType: true,
        assignedDepot: true
      }
    });

    if (!pm) {
      throw new NotFoundError('PM not found');
    }

    // Get labor rates
    const laborRate = await this.getLaborRate(pm.assignedDepotId, pm.targetDate);

    // Get material costs
    const materialCost = await this.calculateMaterialCost(pm.pmType.id);

    // Calculate labor cost
    const hours = pm.actualHours || pm.assignedHours || pm.pmType.estimatedHours;
    const laborCost = hours * laborRate.shopRateHourly;

    // Overtime (if applicable)
    let overtimeCost = 0;
    if (pm.assignedShift === 'NIGHT' || pm.assignedShift === 'WEEKEND') {
      const multiplier = pm.assignedShift === 'WEEKEND' 
        ? laborRate.weekendMultiplier 
        : laborRate.overtimeMultiplier;
      overtimeCost = hours * laborRate.regularHourlyRate * (multiplier - 1);
    }

    // Overhead (typically 15-20% of direct costs)
    const overheadRate = 0.18;
    const directCost = laborCost + materialCost;
    const overheadCost = directCost * overheadRate;

    return {
      laborCost,
      overtimeCost,
      materialCost,
      contractorCost: 0,
      overheadCost,
      totalCost: laborCost + overtimeCost + materialCost + overheadCost
    };
  }

  async projectTCO(
    horizonYears: number = 12
  ): Promise<TCOProjection> {
    const projections: YearlyCost[] = [];
    const startYear = new Date().getFullYear();

    for (let year = 0; year < horizonYears; year++) {
      const fiscalYear = startYear + year;

      // Get scheduled PMs for this year
      const yearStart = new Date(fiscalYear, 0, 1);
      const yearEnd = new Date(fiscalYear, 11, 31);

      const scheduledPMs = await this.db.query.pmSchedule.findMany({
        where: and(
          isNull(pmSchedule.scenarioId),
          gte(pmSchedule.targetDate, yearStart),
          lte(pmSchedule.targetDate, yearEnd)
        ),
        with: { pmType: true }
      });

      // Calculate costs
      let totalLabor = 0;
      let totalMaterial = 0;

      for (const pm of scheduledPMs) {
        const cost = await this.calculatePMCost(pm.id, true);
        totalLabor += cost.laborCost + cost.overtimeCost;
        totalMaterial += cost.materialCost;
      }

      // Apply inflation adjustment for future years
      const inflationRate = 0.03;
      const inflationFactor = Math.pow(1 + inflationRate, year);

      projections.push({
        fiscalYear,
        laborCost: totalLabor * inflationFactor,
        materialCost: totalMaterial * inflationFactor,
        pmCount: scheduledPMs.length,
        inflationFactor
      });
    }

    // Calculate NPV
    const discountRate = 0.05;
    let npv = 0;

    for (let i = 0; i < projections.length; i++) {
      const yearCost = projections[i].laborCost + projections[i].materialCost;
      npv += yearCost / Math.pow(1 + discountRate, i);
    }

    return {
      projections,
      summary: {
        totalLaborCost: projections.reduce((sum, p) => sum + p.laborCost, 0),
        totalMaterialCost: projections.reduce((sum, p) => sum + p.materialCost, 0),
        totalPMCount: projections.reduce((sum, p) => sum + p.pmCount, 0),
        npv,
        avgAnnualCost: npv / horizonYears
      }
    };
  }

  async calculateVariance(
    fiscalYear: number,
    depotId?: string
  ): Promise<CostVariance> {
    const baseline = await this.db.query.costBaselines.findFirst({
      where: and(
        eq(costBaselines.fiscalYear, fiscalYear),
        depotId ? eq(costBaselines.depotId, depotId) : isNull(costBaselines.depotId)
      )
    });

    if (!baseline) {
      throw new NotFoundError('Cost baseline not found');
    }

    // Get actual costs from completed PMs
    const yearStart = new Date(fiscalYear, 0, 1);
    const yearEnd = new Date(fiscalYear, 11, 31);

    const completedPMs = await this.db.query.pmSchedule.findMany({
      where: and(
        eq(pmSchedule.status, 'COMPLETED'),
        gte(pmSchedule.completedAt, yearStart),
        lte(pmSchedule.completedAt, yearEnd),
        depotId ? eq(pmSchedule.assignedDepotId, depotId) : undefined
      )
    });

    let actualLaborCost = 0;
    let actualMaterialCost = 0;

    for (const pm of completedPMs) {
      const cost = await this.calculatePMCost(pm.id);
      actualLaborCost += cost.laborCost + cost.overtimeCost;
      actualMaterialCost += cost.materialCost;
    }

    const actualTotal = actualLaborCost + actualMaterialCost;
    const budgetTotal = baseline.budgetTotal;

    return {
      fiscalYear,
      depotId,
      budget: {
        labor: baseline.budgetLaborCost,
        material: baseline.budgetMaterialCost,
        total: budgetTotal
      },
      actual: {
        labor: actualLaborCost,
        material: actualMaterialCost,
        total: actualTotal
      },
      variance: {
        labor: actualLaborCost - baseline.budgetLaborCost,
        material: actualMaterialCost - baseline.budgetMaterialCost,
        total: actualTotal - budgetTotal,
        percentage: ((actualTotal - budgetTotal) / budgetTotal) * 100
      },
      status: actualTotal <= budgetTotal ? 'UNDER_BUDGET' : 
              actualTotal <= budgetTotal * 1.1 ? 'WITHIN_TOLERANCE' : 'OVER_BUDGET'
    };
  }
}
```

